mapper.select:
SELECT /* @SQLID=SUB0202_0109-01#Sql001 */ * FROM ( SELECT count(*) over () as TOTAL_ROW , TRADE_DATE , GET_DATE AS DELIVERY_DATE , PRODUCT_SHORT_NAME AS SECURITY_TYPE , BRAND_CD AS BRAND_CODE , FORMAL_BRAND_NAME AS BRAND_NAME , TRADE_SHORT_NAME1 AS DETAILS_TRADE , TRADE_SHORT_NAME2 AS DETAILS_TYPE , CAPITAL_GAIN_TAX_IND AS DEPOSIT_TAX , PRICE , NEW_TRADE_PRICE AS OPEN_PRICE , ISSUE_CURRENCY_NAME AS CURRENCY , EXCHANGE_RATE AS FX , QUANTITY , FEE , CONSUMPTION_TAX , ACCRUED_INTEREST_IND AS TRADE_MARKET_REASON , ACCRUED_INTEREST , WITHHOLDING_TAX AS REAL_PROFIT_AND_LOSS , CAPITAL_GAIN_TAX , ACCURATE_AMOUNT , CANCEL_FLG , NEW_TRADE_DATE AS ACQUIRE_DATE FROM (
UNION ALL
UNION ALL
UNION ALL
) ORDER BY
TRADE_DATE , ORDER_NO , BRAND_CD
TRADE_DATE DESC , ORDER_NO DESC , BRAND_CD DESC
BRAND_CD , FORMAL_BRAND_NAME , TRADE_DATE
BRAND_CD DESC , FORMAL_BRAND_NAME DESC , TRADE_DATE DESC
) WHERE ROWNUM <= #{req.maxRowNum}

mapper.sql:
SELECT TH.gyou , min(to_char(TH.TRADE_DATE, 'YYYY/MM/DD')) AS TRADE_DATE , min( TO_CHAR(TH.GET_DATE, 'YYYY/MM/DD') ) AS GET_DATE , min(TH.PRODUCT_SHORT_NAME) AS PRODUCT_SHORT_NAME , min(decode(TH.BRAND_CD, ' ', '', TH.BRAND_CD)) AS BRAND_CD , min(TH.FORMAL_BRAND_NAME) AS FORMAL_BRAND_NAME , min(TH.TRADE_SHORT_NAME1) AS TRADE_SHORT_NAME1 , min(TH.TRADE_SHORT_NAME2) AS TRADE_SHORT_NAME2 , min(TH.CAPITAL_GAIN_TAX_IND) AS CAPITAL_GAIN_TAX_IND , min( replace ( trim( to_char(trunc(TH.PRICE, 4), '99G999G999G990D9999')) , '.0000', '') ) AS PRICE , min( replace ( trim( to_char( trunc(TH.NEW_TRADE_PRICE, 4), '99G999G999G990D9999')) , '.0000', '') ) AS NEW_TRADE_PRICE , min(TH.ISSUE_CURRENCY_NAME) AS ISSUE_CURRENCY_NAME , min( replace ( trim( to_char(trunc(TH.EXCHANGE_RATE, 6), '999G999G990D999999')) , '.000000', '') ) AS EXCHANGE_RATE , min( replace ( trim( to_char(trunc(TH.QUANTITY, 4), '99G999G999G990D9999')) , '.0000', '') ) AS QUANTITY , min( trim(to_char(TH.FEE, '99G999G999G999')) ) AS FEE , min( trim(to_char(TH.CONSUMPTION_TAX, '99G999G999G999')) ) AS CONSUMPTION_TAX , min(TH.ACCRUED_INTEREST_IND) AS ACCRUED_INTEREST_IND , min( trim(to_char(TH.ACCRUED_INTEREST, '99G999G999G999')) ) AS ACCRUED_INTEREST , min( trim(to_char(TH.WITHHOLDING_TAX, '99G999G999G999')) ) AS WITHHOLDING_TAX , min( trim(to_char(TH.CAPITAL_GAIN_TAX, '99G999G999G999')) ) AS CAPITAL_GAIN_TAX , min( trim(to_char(TH.ACCURATE_AMOUNT, '9G999G999G999G999')) ) AS ACCURATE_AMOUNT , min(nvl(TH.CANCEL_FLG, 0)) AS CANCEL_FLG
, '' AS NEW_TRADE_DATE
, min( decode( THT.NEW_TRADE_DATE, '1 ', '', '1', '', '', '', substr(THT.NEW_TRADE_DATE, 1, 4) || '/' || substr(THT.NEW_TRADE_DATE, 5, 2) || '/' || substr(THT.NEW_TRADE_DATE, 7, 2)) ) AS NEW_TRADE_DATE
, min(TH.ORDER_NO) AS ORDER_NO FROM ( SELECT ROWNUM as gyou , CUSTOMER_ID , BRANCH_NO , ACCOUNT_NO , SEARCH_TRADE_S_CD , BRAND_CD , FORMAL_BRAND_NAME , TRADE_DATE , GET_DATE , ORDER_NO , PRODUCT_SHORT_NAME , TRADE_SHORT_NAME1 , TRADE_SHORT_NAME2 , CAPITAL_GAIN_TAX_IND , PRICE , NEW_TRADE_PRICE , ISSUE_CURRENCY_NAME , EXCHANGE_RATE , QUANTITY , FEE , CONSUMPTION_TAX , ACCRUED_INTEREST_IND , ACCRUED_INTEREST , WITHHOLDING_TAX , CAPITAL_GAIN_TAX , ACCURATE_AMOUNT , CANCEL_FLG , SEARCH_TRADE_L_CD , SEARCH_TRADE_M_CD , SEARCH_PRODUCT_S_CD , SEARCH_PRODUCT_M_CD , SEARCH_PRODUCT_L_CD FROM ETINTRA.TRADE_HISTORY WHERE CUSTOMER_ID = #{req.customerCode} AND TRADE_DATE between to_date(#{req.periodFrom}, 'YYYY/MM/DD') AND to_date(#{req.periodTo}, 'YYYY/MM/DD') +1 - (1/86400)
AND SEARCH_TRADE_L_CD <> 'D'
AND SEARCH_TRADE_L_CD = 'D'
AND NOT EXISTS (
SELECT 1 FROM ETINTRA.TRADE_HISTORY_TRUST THT WHERE
)
AND SEARCH_PRODUCT_S_CD = #{req.securitySearchCodeSmallClass}
AND SEARCH_PRODUCT_M_CD = #{req.securitySearchCodeMidClass}
AND SEARCH_PRODUCT_L_CD = #{req.securitySearchCodeBigClass}
AND SEARCH_TRADE_S_CD = #{req.tradeSearchCodeSmallClass}
AND SEARCH_TRADE_M_CD = #{req.tradeSearchCodeMidClass}
AND SEARCH_TRADE_L_CD = #{req.tradeSearchCodeBigClass}
AND BRAND_CD = #{req.brandCode}
) TH
, ETINTRA.TRADE_HISTORY_TRUST THT WHERE
GROUP BY GYOU
